from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Optional
import uuid

app = FastAPI(title="Agent Registry API")

# ── schemas ────────────────────────────────────────────────────────────────
class AgentCreate(BaseModel):
    name: str
    model: str
    system_prompt: Optional[str] = None

class Agent(AgentCreate):
    id: str

# ── in-memory store (swap for DB in production) ────────────────────────────
_store: dict[str, Agent] = {}

# ── endpoints ──────────────────────────────────────────────────────────────
@app.get("/agents", response_model=list[Agent])
def list_agents():
    return list(_store.values())

@app.post("/agents", response_model=Agent, status_code=201)
def create_agent(body: AgentCreate):
    agent = Agent(id=str(uuid.uuid4()), **body.model_dump())
    _store[agent.id] = agent
    return agent

@app.get("/agents/{agent_id}", response_model=Agent)
def get_agent(agent_id: str):
    if agent_id not in _store:
        raise HTTPException(status_code=404, detail="Agent not found")
    return _store[agent_id]

@app.put("/agents/{agent_id}", response_model=Agent)
def update_agent(agent_id: str, body: AgentCreate):
    if agent_id not in _store:
        raise HTTPException(status_code=404, detail="Agent not found")
    updated = Agent(id=agent_id, **body.model_dump())
    _store[agent_id] = updated
    return updated

@app.delete("/agents/{agent_id}", status_code=204)
def delete_agent(agent_id: str):
    if agent_id not in _store:
        raise HTTPException(status_code=404, detail="Agent not found")
    del _store[agent_id]

# ✗ Wrong — returns 200 even on failure, forces clients to parse body
@app.post("/agents")
def create_agent(body: AgentCreate):
    try:
        ...
    except ValueError as e:
        return {"error": str(e)}  # status 200!

# ✓ Correct — use HTTPException so clients can branch on status code
@app.post("/agents", status_code=201)
def create_agent(body: AgentCreate):
    try:
        ...
    except ValueError as e:
        raise HTTPException(status_code=422, detail=str(e))

# ✗ Wrong — each endpoint returns a different error format
@app.get("/agents/{id}")
def get_agent(id: str):
    ...  # returns {"message": "Not found"}

@app.post("/agents")
def create_agent(body: AgentCreate):
    ...  # returns "error: duplicate name"

# ✓ Correct — use a consistent error schema. FastAPI's HTTPException
# returns {"detail": "..."} by default. Override with an exception handler
# for richer error envelopes:
from fastapi.responses import JSONResponse
from fastapi.exceptions import RequestValidationError

@app.exception_handler(RequestValidationError)
async def validation_error_handler(request, exc):
    return JSONResponse(
        status_code=422,
        content={"code": "VALIDATION_ERROR", "errors": exc.errors()},
    )
